class axi_driver #(
    parameter int  AW = 32  ,
    parameter int  IW = 8   ,
    parameter int  UW = 1
  );
    typedef axi_ax_beat #(.AW(AW), .IW(IW), .UW(UW)) ax_beat_t;
  endclass

  typedef axi_test::axi_driver #(
    .AW(TbAddrWidth), .IW(TbIdWidth), .UW(TbUserWidth)
  ) drv_t;

  automatic drv_t::ax_beat_t aw_beat = new;

class axi_ax_beat #(
    parameter AW = 32,
    parameter IW = 8,
    parameter UW = 1
  );
    rand logic [IW-1:0] ax_id     = '0;
    rand logic [AW-1:0] ax_addr   = '0;
    rand logic [UW-1:0] ax_user   = '0;
  endclass

